import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.SQLException;
import java.sql.Statement;
import java.sql.ResultSet;

/**
 * JDBC Database Connection Example
 * Demonstrates complete JDBC connection workflow
 */
public class JDBCConnectionDemo {

 // Database configuration constants
 private static final String DB_URL = "jdbc:mysql://localhost:3306/school";
 private static final String USER = "root";
 private static final String PASSWORD = "password";
 private static final String DRIVER = "com.mysql.cj.jdbc.Driver";

 public static void main(String[] args) {
 Connection connection = null;
 Statement statement = null;
 ResultSet resultSet = null;

 try {
 // Step 1: Load and register JDBC driver (optional in JDBC 4.0+)
 Class.forName(DRIVER);
 System.out.println("JDBC Driver loaded successfully!");

 // Step 2: Establish connection using DriverManager
 connection = DriverManager.getConnection(DB_URL, USER, PASSWORD);
 System.out.println("Connected to database successfully!");

 // Step 3: Create Statement object
 statement = connection.createStatement();

 // Step 4: Execute SQL query
 String sql = "SELECT id, name, age, grade FROM students";
 resultSet = statement.executeQuery(sql);

 // Step 5: Process ResultSet
 System.out.println("\nStudent Records:");
 System.out.println("-" * 40);
 while (resultSet.next()) {
 int id = resultSet.getInt("id");
 String name = resultSet.getString("name");
 int age = resultSet.getInt("age");
 String grade = resultSet.getString("grade");

 System.out.printf("ID: %d | Name: %s | Age: %d | Grade: %s%n", 
 id, name, age, grade);
 }

 } catch (ClassNotFoundException e) {
 System.out.println("JDBC Driver not found!");
 e.printStackTrace();
 } catch (SQLException e) {
 System.out.println("Database connection failed!");
 e.printStackTrace();
 } finally {
 // Step 6: Close resources in reverse order
 try {
 if (resultSet != null) resultSet.close();
 if (statement != null) statement.close();
 if (connection != null) connection.close();
 System.out.println("\nResources closed successfully!");
 } catch (SQLException e) {
 e.printStackTrace();
 }
 }
 }
}

/**
 * Alternative: Using try-with-resources (Java 7+)
 * Automatically closes resources - recommended approach
 */
class JDBCTryWithResourcesDemo {
 private static final String DB_URL = "jdbc:mysql://localhost:3306/school";
 private static final String USER = "root";
 private static final String PASS = "password";

 public static void main(String[] args) {
 // Try-with-resources automatically closes resources
 try (Connection conn = DriverManager.getConnection(DB_URL, USER, PASS);
 Statement stmt = conn.createStatement();
 ResultSet rs = stmt.executeQuery("SELECT * FROM students")) {

 System.out.println("Connected successfully using try-with-resources!");

 while (rs.next()) {
 System.out.println(rs.getInt(1) + ": " + rs.getString(2));
 }

 } catch (SQLException e) {
 e.printStackTrace();
 }
 // Resources automatically closed here!
 }
}

import java.sql.Connection;
import java.sql.ResultSet;
import java.sql.Statement;
import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;

/**
 * JDBC Connection Pooling Example using HikariCP
 * Connection pooling improves performance by reusing connections
 */
public class ConnectionPoolDemo {

 // HikariCP connection pool
 private static HikariDataSource dataSource;

 static {
 // Configure connection pool
 HikariConfig config = new HikariConfig();
 config.setJdbcUrl("jdbc:mysql://localhost:3306/school");
 config.setUsername("root");
 config.setPassword("password");
 config.setDriverClassName("com.mysql.cj.jdbc.Driver");

 // Pool configuration
 config.setMaximumPoolSize(10); // Maximum connections
 config.setMinimumIdle(2); // Minimum idle connections
 config.setIdleTimeout(300000); // Idle timeout (5 minutes)
 config.setConnectionTimeout(20000); // Connection timeout (20 sec)
 config.setMaxLifetime(1800000); // Max lifetime (30 minutes)

 // Initialize data source
 dataSource = new HikariDataSource(config);
 }

 /**
 * Get connection from pool
 */
 public static Connection getConnection() throws Exception {
 return dataSource.getConnection();
 }

 /**
 * Query example using pooled connection
 */
 public static void fetchStudents() {
 String sql = "SELECT id, name, grade FROM students";

 // Connection is automatically returned to pool after use
 try (Connection conn = getConnection();
 Statement stmt = conn.createStatement();
 ResultSet rs = stmt.executeQuery(sql)) {

 System.out.println("Using pooled connection!");
 while (rs.next()) {
 System.out.println(rs.getInt("id") + ": " + rs.getString("name"));
 }

 } catch (Exception e) {
 e.printStackTrace();
 }
 }

 /**
 * Close connection pool (call on application shutdown)
 */
 public static void shutdown() {
 if (dataSource != null) {
 dataSource.close();
 System.out.println("Connection pool closed!");
 }
 }

 public static void main(String[] args) {
 // Simulate multiple database operations
 for (int i = 0; i < 5; i++) {
 System.out.println("\n--- Request " + (i + 1) + " ---");
 fetchStudents();
 }

 // Clean shutdown
 shutdown();
 }
}

